SELECT baseline."in.comstock_building_type" AS comstock_building_type, date_trunc('month', date_add('second', -900, comstock_amy2018_r2_2025_ts_by_state.timestamp)) AS timestamp, count(DISTINCT (baseline.bldg_id, baseline."in.nhgis_tract_gisjoin", baseline.state)) AS sample_count, (count(DISTINCT (baseline.bldg_id, baseline."in.nhgis_tract_gisjoin", baseline.state)) * sum(baseline.weight)) / CAST(sum(1) AS DECIMAL) AS units_count, sum(1) / CAST(count(DISTINCT (baseline.bldg_id, baseline."in.nhgis_tract_gisjoin", baseline.state)) AS DECIMAL) AS rows_per_sample, sum(comstock_amy2018_r2_2025_ts_by_state."out.electricity.total.energy_consumption" * baseline.weight) AS "electricity.total.energy_consumption", sum(comstock_amy2018_r2_2025_ts_by_state."out.natural_gas.total.energy_consumption" * baseline.weight) AS "natural_gas.total.energy_consumption" FROM comstock_amy2018_r2_2025_ts_by_state JOIN (SELECT * FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade = 0) AS baseline ON baseline.bldg_id = comstock_amy2018_r2_2025_ts_by_state.bldg_id AND baseline.state = comstock_amy2018_r2_2025_ts_by_state.state AND comstock_amy2018_r2_2025_ts_by_state.upgrade = 0 AND comstock_amy2018_r2_2025_ts_by_state.state IN ('CO', 'NM') AND baseline.state IN ('CO', 'NM') WHERE baseline.state IN ('CO', 'NM') GROUP BY 1, 2 ORDER BY 1, 2